import type { CancelTokenSource } from './cancel-token';
import { wait } from './utils';

/**
 * @en The class manages lumping multiple `Promise` objects. <br>
 *     It's possible to make them cancel more than one `Promise` which handles different {@link CancelToken} by lumping.
 * @ja كجçµـ░ `Promise` عéزعâûعé╕عéدعé»عâêعéْغ╕µïشق«ةقعآعéïعé»عâرعé╣ <br>
 *     قـ░عزعéï {@link CancelToken} عéْµë▒عكجçµـ░ع« `Promise` عéْغ╕µïشعدعéصعâثعâ│عé╗عâسعـعؤعéïعôعذعîف»كâ╜
 */
export class PromiseManager {
    private readonly _pool = new Map<Promise<unknown>, ((reason: unknown) => unknown) | undefined>();

    /**
     * @en Add a `Promise` object under the management.
     * @ja `Promise` عéزعâûعé╕عéدعé»عâêعéْق«ةقغ╕ïعسك┐╜فèب
     *
     * @param promise
     *  - `en` any `Promise` instance is available.
     *  - `ja` غ╗╗µع« `Promise` عéجعâ│عé╣عé┐عâ│عé╣
     * @param cancelSource
     *  - `en` {@link CancelTokenSource} instance made by {@link CancelToken.source | CancelToken.source}().
     *  - `ja` {@link CancelToken.source | CancelToken.source}() عدق¤اµêعـعéîعéï {@link CancelTokenSource} عéجعâ│عé╣عé┐عâ│عé╣
     * @returns
     *  - `en` return the same instance of input `promise` instance.
     *  - `ja` فàحفèؤعùعا `promise` عذفîغ╕عéجعâ│عé╣عé┐عâ│عé╣عéْك┐¤ف┤
     */
    public add<T>(promise: Promise<T>, cancelSource?: CancelTokenSource): Promise<T> {
        this._pool.set(promise, cancelSource?.cancel); // eslint-disable-line @typescript-eslint/unbound-method

        const always = (): void => {
            this._pool.delete(promise);
            if (cancelSource) {
                cancelSource.close();
            }
        };

        promise
            .then(always, always);

        return promise;
    }

    /**
     * @en Released all instances under the management.
     * @ja ق«ةقف»╛ك▒ةعéْقب┤µث
     */
    public release(): void {
        this._pool.clear();
    }

    /**
     * @en Return `promise` array from under the management.
     * @ja ق«ةقف»╛ك▒ةع« Promise عéْلàفêùعدفûف╛ù
     */
    public promises(): Promise<unknown>[] {
        return [...this._pool.keys()];
    }

    /**
     * @en Call `Promise.all()` for under the management. <br>
     *     Wait for all `fulfilled`.
     * @ja ق«ةقف»╛ك▒ةعسف»╛عùعخ `Promise.all()` <br>
     *     عآع╣عخعî `fulfilled` عسعزعéïع╛عدف╛àµرا
     */
    public all(): Promise<unknown[]> {
        return Promise.all(this.promises());
    }

    /**
     * @en Call `Promise.race()` for under the management. <br>
     *     Wait for any `settled`.
     * @ja ق«ةقف»╛ك▒ةعسف»╛عùعخ `Promise.race()` <br>
     *     ععأعéîعïعî `settled` عسعزعéïع╛عدف╛àµرا
     */
    public race(): Promise<unknown> {
        return Promise.race(this.promises());
    }

    /**
     * @en Call {@link wait}() for under the management. <br>
     *     Wait for all `settled`. (simplified version)
     * @ja ق«ةقف»╛ك▒ةعسف»╛عùعخ {@link wait}() <br>
     *     عآع╣عخعî `settled` عسعزعéïع╛عدف╛àµرا (ق░ةµءôعâعâ╝عé╕عâدعâ│)
     */
    public wait(): Promise<unknown[]> {
        return wait(this.promises());
    }

    /**
     * @en Call `Promise.allSettled()` for under the management. <br>
     *     Wait for all `settled`.
     * @ja ق«ةقف»╛ك▒ةعسف»╛عùعخ `Promise.allSettled()` <br>
     *     عآع╣عخعî `settled` عسعزعéïع╛عدف╛àµرا
     */
    public allSettled(): Promise<PromiseSettledResult<unknown>[]> {
        return Promise.allSettled(this.promises());
    }

    /**
     * @en Call `Promise.any()` for under the management. <br>
     *     Wait for any `fulfilled`.
     * @ja ق«ةقف»╛ك▒ةعسف»╛عùعخ `Promise.any()` <br>
     *     ععأعéîعïعî `fulfilled` عسعزعéïع╛عدف╛àµرا
     */
    public any(): Promise<unknown> {
        return Promise.any(this.promises());
    }

    /**
     * @en Invoke `cancel` message for under the management promises.
     * @ja ق«ةقف»╛ك▒ةع« `Promise` عسف»╛عùعخعéصعâثعâ│عé╗عâسعéْقآ║كةî
     *
     * @param reason
     *  - `en` arguments for `cancelSource`
     *  - `ja` `cancelSource` عسµ╕ةعـعéîعéïف╝ـµـ░
     * @returns
     *  - `en` `Promise` instance which wait by until cancellation completion.
     *  - `ja` عéصعâثعâ│عé╗عâسف«îغ║ع╛عدف╛àµراعآعéï `Promise` عéجعâ│عé╣عé┐عâ│عé╣
     */
    public abort<T>(reason?: T): Promise<unknown[]> {
        for (const canceler of this._pool.values()) {
            if (canceler) {
                canceler(
                    reason ?? new Error('abort')
                );
            }
        }
        return wait(this.promises());
    }
}
