const _initialRoutes: RouteParameters[] = [];

/**
 * @en Route parameters for page registration. Need to describe `path`, `content`.
 * @ja عâأعâ╝عé╕قآ╗لî▓ق¤ذعâسعâ╝عâêعâّعâرعâةعâ╝عé┐. `path`, `content` ع«كذءك┐░عîف┐àكخ
 */
export type PageRouteParameters = Required<Pick<RouteParameters, 'content'>> & RouteParameters;

/**
 * @en Pre-register concrete {@link Page} class. Registered with the main router when instantiating {@link AppContext}. <br>
 *     If constructor needs arguments, `options.componentOptions` is available.
 * @ja Page فà╖ك▒ةفîûعé»عâرعé╣ع«غ║ïفëقآ╗لî▓. {@link AppContext} ع«عéجعâ│عé╣عé┐عâ│عé╣فîûµآéعسعâةعéجعâ│عâسعâ╝عé┐عâ╝عسقآ╗لî▓عـعéîعéï. <br>
 *     constructor عéْµîçف«أعآعéïف╝ـµـ░عîعéعéïفب┤فêع», `options.componentOptions` عéْفêرق¤ذف»كâ╜
 *
 * @example <br>
 *
 * ```ts
 * import {
 *     Page,
 *     Router,
 *     AppContext,
 *     registerPage,
 * } from '@cdp/runtime';
 *
 * const pageFactory = (router: Router, ...args: any[]): Page => {
 *   :
 * };
 *
 * // pre-registration
 * registerPage({
 *     path: 'page-path',
 *     conponent: pageFactory,
 *     content: '#page-id'
 * });
 *
 * // initial access
 * const app = AppContext({ main: '#app' });
 * :
 * ```
 *
 * @param path
 *  - `en` route path
 *  - `ja` عâسعâ╝عâêع«عâّعé╣
 * @param component
 *  - `en` specify the constructor or built object of the page component
 *  - `ja` عâأعâ╝عé╕عé│عâ│عâإعâ╝عâعâ│عâêع«عé│عâ│عé╣عâêعâرعé»عé┐عééعùعع»µدïق»ëµ╕êع┐عéزعâûعé╕عéدعé»عâê
 * @param options
 *  - `en` route parameters
 *  - `ja` عâسعâ╝عâêعâّعâرعâةعâ╝عé┐
 */
export const registerPage = (params: PageRouteParameters): void => {
    _initialRoutes.push(params);
};

