/**
 * @en Check the value instance of input constructor (except sub class).
 * @ja µîçف«أعé│عâ│عé╣عâêعâرعé»عé┐ع«عéجعâ│عé╣عé┐عâ│عé╣عدعéعéïعïفêجف«أ (µ┤╛ق¤اعé»عâرعé╣ع»فسعéعزع)
 *
 * @param ctor
 *  - `en` evaluated constructor
 *  - `ja` كرـغ╛ةعآعéïعé│عâ│عé╣عâêعâرعé»عé┐
 * @param x
 *  - `en` evaluated value
 *  - `ja` كرـغ╛ةعآعéïفج
 */
export function ownInstanceOf<T extends object>(ctor: Nullable<Type<T>>, x: unknown): x is T {
    return (null != x) && ('function' === typeof ctor) && (Object.getPrototypeOf(x) === Object(ctor.prototype));
}

/**
 * @en Get the value's class name.
 * @ja عé»عâرعé╣فعéْفûف╛ù
 *
 * @param x
 *  - `en` evaluated value
 *  - `ja` كرـغ╛ةعآعéïفج
 */
export function className(x: any): string {
    if (x != null) {
        const toStringTagName = x[Symbol.toStringTag];
        if (isString(toStringTagName)) {
            return toStringTagName;
        } else if (isFunction(x) && x.prototype && null != x.name) {
            return x.name;
        } else {
            const ctor = x.constructor;
            if (isFunction(ctor) && ctor === (Object(ctor.prototype) as object).constructor) {
                return ctor.name;
            }
        }
    }
    return (Object.prototype.toString.call(x) as string).slice(8, -1);
}

