import { location, document } from './ssr';

/**
 * @en Get the directory to which `url` belongs.
 * @ja µîçف«أ `url` ع«µëف▒ئعآعéïعâçعéثعâشعé»عâêعâزعéْفûف╛ù
 *
 * @param url
 *  - `en` target URL
 *  - `ja` ف»╛ك▒ةع« URL
 */
export const getWebDirectory = (url: string): string => {
    const match = /^(([^?#]+)\/)([\S]*)?$/.exec(url);
    return match?.[1] ?? '';
};

/**
 * @en Accsessor for Web root location <br>
 *     Only the browser environment will be an allocating place in index.html, and becomes effective.
 * @ja Web root location ع╕ع«عéتعé»عé╗عé╣ <br>
 *     index.html ع«لàق╜«فب┤µëعذعزعéèععâûعâرعéخعé╢قْ░فتâع«ع┐µ£ëفè╣عذعزعéï.
 */
export const webRoot: string = getWebDirectory(document.querySelector('base')?.getAttribute('href') ?? location.href);

/**
 * @en Convert to an absolute url string if given a relative path. <br>
 *     If you want to access to Assets and in spite of the script location, the function is available.
 * @ja قؤ╕ف»╛عâّعé╣عîµîçف«أعـعéîعخععéïفب┤فêع»عق╡╢ف»╛URLµûçفصùفêùعسفجëµؤ <br>
 *     js ع«لàق╜«عسغ╛إفصءعآعéïعôعذعزع `assets` عéتعé»عé╗عé╣عùعاععذععسغ╜┐ق¤ذعآعéï.
 *
 * @see https://stackoverflow.com/questions/2188218/relative-paths-in-javascript-in-an-external-file
 *
 * @example <br>
 *
 * ```ts
 *  console.log(toUrl('/res/data/collection.json'));
 *  // "http://localhost:8080/app/res/data/collection.json"
 * ```
 *
 * @param seed
 *  - `en` set relative path from {@link webRoot}.
 *  - `ja` {@link webRoot} عïعéëع«قؤ╕ف»╛عâّعé╣عéْµîçف«أ
 */
export const toUrl = (seed: string): string => {
    if (seed?.includes('://')) {
        return seed;
    } else if (null != seed?.[0]) {
        return ('/' === seed[0]) ? webRoot + seed.slice(1) : webRoot + seed;
    } else {
        return webRoot;
    }
};
